--方块物品池
BlockGoodsPool = {}
--BlockGoodsPool.BlockPool = {}
BlockGoodsPool.Items = {}
function BlockGoodsPool:init(configs)
    for _, config in pairs(configs) do
        local item = {}
        item.id = tonumber(config.id)
        item.itemId = tonumber(config.itemId)
        item.poolId = tonumber(config.poolId) or 0
        item.count = tonumber(config.count) or 1
        item.weight = tonumber(config.weight) or 0
        item.name = tostring(config.name) or ""
        item.describe = tostring(config.describe) or ""
        self.Items[item.id] = item
        if item.poolId ~= 0 then
            BlockGoodsManager:addBlockGoodsToPools(item)
        end
    end
end

return BlockGoodsPool